import{_ as s,c as a,e as p,o as e}from"./app-Ct2V40Uz.js";const t={};function l(c,n){return e(),a("div",null,[...n[0]||(n[0]=[p(`<h1 id="qt-6-实战-c-调用-qml-回调方法-异步场景完整实现" tabindex="-1"><a class="header-anchor" href="#qt-6-实战-c-调用-qml-回调方法-异步场景完整实现"><span>Qt 6 实战：C++ 调用 QML 回调方法（异步场景完整实现）</span></a></h1><p>在 Qt 6 开发中，C++ 与 QML 混合编程是常见场景。当 C++ 处理异步操作（如登录验证、网络请求、数据库查询）时，需要将结果通知给 QML 界面，<strong>回调函数</strong>是最直观的通信方式之一。本文将基于你提供的代码框架，补充关键细节、修复潜在问题，并完整实现从 C++ 调用 QML 回调的全流程。</p><h2 id="一、核心场景说明" tabindex="-1"><a class="header-anchor" href="#一、核心场景说明"><span>一、核心场景说明</span></a></h2><p>我们需要实现：</p><ol><li>QML 调用 C++ 的 <code>login</code> 方法（传入用户名、密码和两个回调函数：成功回调 <code>onSuccess</code>、失败回调 <code>onFailure</code>）；</li><li>C++ 异步处理登录逻辑（模拟耗时操作）；</li><li>登录完成后，C++ 调用对应的 QML 回调函数，将结果（成功响应 / 错误信息）传递给 QML。</li></ol><h2 id="二、step-1-完善-c-服务类" tabindex="-1"><a class="header-anchor" href="#二、step-1-完善-c-服务类"><span>二、Step 1：完善 C++ 服务类</span></a></h2><h3 id="_1-1-基础配置-必须继承-qobject" tabindex="-1"><a class="header-anchor" href="#_1-1-基础配置-必须继承-qobject"><span>1.1 基础配置（必须继承 QObject）</span></a></h3><p>QML 能调用的 C++ 方法 / 属性，依赖 Qt 的元对象系统（MOC），因此 <code>AuthenticationService</code> 必须：</p><ul><li>继承 <code>QObject</code>；</li><li>添加 <code>Q_OBJECT</code> 宏；</li><li>用 <code>Q_INVOKABLE</code> 标记需要暴露给 QML 的方法。</li></ul><h3 id="_1-2-完整-c-代码实现" tabindex="-1"><a class="header-anchor" href="#_1-2-完整-c-代码实现"><span>1.2 完整 C++ 代码实现</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// authentication_service.h</span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QObject&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QJSValue&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QJSEngine&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QtConcurrent&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QThread&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QMetaObject&gt;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 自定义错误类：封装错误码、错误信息</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">KratosError</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    <span class="token function">KratosError</span><span class="token punctuation">(</span><span class="token keyword">int</span> code<span class="token punctuation">,</span> <span class="token keyword">const</span> QString<span class="token operator">&amp;</span> message<span class="token punctuation">,</span> <span class="token keyword">const</span> QString<span class="token operator">&amp;</span> details <span class="token operator">=</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token operator">:</span> <span class="token function">m_code</span><span class="token punctuation">(</span>code<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token function">m_message</span><span class="token punctuation">(</span>message<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token function">m_details</span><span class="token punctuation">(</span>details<span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 转换为 QJSValue，供 QML 访问属性</span></span>
<span class="line">    QJSValue <span class="token function">toQJSValue</span><span class="token punctuation">(</span>QJSEngine<span class="token operator">&amp;</span> engine<span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span></span>
<span class="line">        QJSValue errorObj <span class="token operator">=</span> engine<span class="token punctuation">.</span><span class="token function">newObject</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        errorObj<span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;code&quot;</span><span class="token punctuation">,</span> m_code<span class="token punctuation">)</span><span class="token punctuation">;</span>       <span class="token comment">// 错误码（如 401 未授权）</span></span>
<span class="line">        errorObj<span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;message&quot;</span><span class="token punctuation">,</span> m_message<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 错误提示</span></span>
<span class="line">        errorObj<span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;details&quot;</span><span class="token punctuation">,</span> m_details<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 详细信息（可选）</span></span>
<span class="line">        <span class="token keyword">return</span> errorObj<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">    <span class="token keyword">int</span> m_code<span class="token punctuation">;</span></span>
<span class="line">    QString m_message<span class="token punctuation">;</span></span>
<span class="line">    QString m_details<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 登录成功响应类：封装返回数据</span></span>
<span class="line"><span class="token keyword">struct</span> <span class="token class-name">LoginResponse</span> <span class="token punctuation">{</span></span>
<span class="line">    QString token<span class="token punctuation">;</span>     <span class="token comment">// 身份令牌</span></span>
<span class="line">    QString username<span class="token punctuation">;</span>  <span class="token comment">// 用户名</span></span>
<span class="line">    <span class="token keyword">int</span> userId<span class="token punctuation">;</span>        <span class="token comment">// 用户 ID</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 转换为 QJSValue，供 QML 访问属性</span></span>
<span class="line">    QJSValue <span class="token function">toQJSValue</span><span class="token punctuation">(</span>QJSEngine<span class="token operator">&amp;</span> engine<span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span></span>
<span class="line">        QJSValue respObj <span class="token operator">=</span> engine<span class="token punctuation">.</span><span class="token function">newObject</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        respObj<span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;token&quot;</span><span class="token punctuation">,</span> token<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        respObj<span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;username&quot;</span><span class="token punctuation">,</span> username<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        respObj<span class="token punctuation">.</span><span class="token function">setProperty</span><span class="token punctuation">(</span><span class="token string">&quot;userId&quot;</span><span class="token punctuation">,</span> userId<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">return</span> respObj<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 认证服务类（单例模式）</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">AuthenticationService</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">QObject</span></span> <span class="token punctuation">{</span></span>
<span class="line">    Q_OBJECT <span class="token comment">// 必须添加，启用元对象系统</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    <span class="token comment">// 单例获取方法（线程安全）</span></span>
<span class="line">    <span class="token keyword">static</span> AuthenticationService<span class="token operator">*</span> <span class="token function">instance</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">static</span> QMutex mutex<span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>m_instance<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            mutex<span class="token punctuation">.</span><span class="token function">lock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>m_instance<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                m_instance <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token function">AuthenticationService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">            mutex<span class="token punctuation">.</span><span class="token function">unlock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        <span class="token keyword">return</span> m_instance<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 禁止拷贝构造和赋值</span></span>
<span class="line">    <span class="token function">AuthenticationService</span><span class="token punctuation">(</span><span class="token keyword">const</span> AuthenticationService<span class="token operator">&amp;</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token keyword">delete</span><span class="token punctuation">;</span></span>
<span class="line">    AuthenticationService<span class="token operator">&amp;</span> <span class="token keyword">operator</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token keyword">const</span> AuthenticationService<span class="token operator">&amp;</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token keyword">delete</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 暴露给 QML 的登录方法</span></span>
<span class="line">    Q_INVOKABLE <span class="token keyword">void</span> <span class="token function">login</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token keyword">const</span> QString<span class="token operator">&amp;</span> username<span class="token punctuation">,</span></span>
<span class="line">        <span class="token keyword">const</span> QString<span class="token operator">&amp;</span> password<span class="token punctuation">,</span></span>
<span class="line">        <span class="token keyword">const</span> QJSValue<span class="token operator">&amp;</span> onSuccess<span class="token punctuation">,</span>  <span class="token comment">// QML 传入的成功回调</span></span>
<span class="line">        <span class="token keyword">const</span> QJSValue<span class="token operator">&amp;</span> onFailure   <span class="token comment">// QML 传入的失败回调</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">    <span class="token function">AuthenticationService</span><span class="token punctuation">(</span>QObject<span class="token operator">*</span> parent <span class="token operator">=</span> <span class="token keyword">nullptr</span><span class="token punctuation">)</span> <span class="token operator">:</span> <span class="token function">QObject</span><span class="token punctuation">(</span>parent<span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">static</span> AuthenticationService<span class="token operator">*</span> m_instance<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// authentication_service.cpp</span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;authentication_service.h&quot;</span></span></span>
<span class="line"></span>
<span class="line">AuthenticationService<span class="token operator">*</span> AuthenticationService<span class="token double-colon punctuation">::</span>m_instance <span class="token operator">=</span> <span class="token keyword">nullptr</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">void</span> <span class="token class-name">AuthenticationService</span><span class="token double-colon punctuation">::</span><span class="token function">login</span><span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">const</span> QString<span class="token operator">&amp;</span> username<span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">const</span> QString<span class="token operator">&amp;</span> password<span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">const</span> QJSValue<span class="token operator">&amp;</span> onSuccess<span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">const</span> QJSValue<span class="token operator">&amp;</span> onFailure</span>
<span class="line"><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 1. 有效性检查：确保 QJSEngine 和回调函数有效</span></span>
<span class="line">    QJSEngine<span class="token operator">*</span> engine <span class="token operator">=</span> <span class="token function">qjsEngine</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>engine<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">qWarning</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&lt;&lt;</span> <span class="token string">&quot;[AuthService] 失败：无法获取 QJSEngine 上下文&quot;</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">return</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>onSuccess<span class="token punctuation">.</span><span class="token function">isCallable</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span>onFailure<span class="token punctuation">.</span><span class="token function">isCallable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">qWarning</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&lt;&lt;</span> <span class="token string">&quot;[AuthService] 警告：未传入有效回调函数&quot;</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">return</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 2. 异步处理登录逻辑（模拟耗时操作：如网络请求、数据库验证）</span></span>
<span class="line">    <span class="token comment">// 用 QtConcurrent::run 开启后台线程，避免阻塞 UI 线程</span></span>
<span class="line">    <span class="token class-name">QtConcurrent</span><span class="token double-colon punctuation">::</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token operator">=</span><span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// 模拟耗时 2 秒（实际场景替换为真实登录逻辑）</span></span>
<span class="line">        <span class="token class-name">QThread</span><span class="token double-colon punctuation">::</span><span class="token function">sleep</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">        <span class="token comment">// 3. 模拟登录验证结果（实际场景替换为真实校验逻辑）</span></span>
<span class="line">        <span class="token keyword">bool</span> isLoginSuccess <span class="token operator">=</span> <span class="token punctuation">(</span>username <span class="token operator">==</span> <span class="token string">&quot;admin&quot;</span> <span class="token operator">&amp;&amp;</span> password <span class="token operator">==</span> <span class="token string">&quot;123456&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">        <span class="token comment">// 4. 切换回主线程执行回调（关键！QJSValue 必须在创建它的线程调用）</span></span>
<span class="line">        <span class="token class-name">QMetaObject</span><span class="token double-colon punctuation">::</span><span class="token function">invokeMethod</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token operator">=</span><span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token punctuation">(</span>isLoginSuccess<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token comment">// 登录成功：构造响应对象，调用 onSuccess 回调</span></span>
<span class="line">                <span class="token keyword">if</span> <span class="token punctuation">(</span>onSuccess<span class="token punctuation">.</span><span class="token function">isCallable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                    LoginResponse resp<span class="token punctuation">;</span></span>
<span class="line">                    resp<span class="token punctuation">.</span>token <span class="token operator">=</span> <span class="token string">&quot;eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...&quot;</span><span class="token punctuation">;</span></span>
<span class="line">                    resp<span class="token punctuation">.</span>username <span class="token operator">=</span> username<span class="token punctuation">;</span></span>
<span class="line">                    resp<span class="token punctuation">.</span>userId <span class="token operator">=</span> <span class="token number">1001</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">                    QJSValueList args<span class="token punctuation">;</span></span>
<span class="line">                    args <span class="token operator">&lt;&lt;</span> resp<span class="token punctuation">.</span><span class="token function">toQJSValue</span><span class="token punctuation">(</span><span class="token operator">*</span>engine<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 传入响应数据</span></span>
<span class="line">                    onSuccess<span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span><span class="token punctuation">;</span>             <span class="token comment">// 调用 QML 成功回调</span></span>
<span class="line">                <span class="token punctuation">}</span></span>
<span class="line">            <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token comment">// 登录失败：构造错误对象，调用 onFailure 回调</span></span>
<span class="line">                <span class="token keyword">if</span> <span class="token punctuation">(</span>onFailure<span class="token punctuation">.</span><span class="token function">isCallable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                    KratosError <span class="token function">error</span><span class="token punctuation">(</span><span class="token number">401</span><span class="token punctuation">,</span> <span class="token string">&quot;登录失败&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;用户名或密码错误&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">                    QJSValueList args<span class="token punctuation">;</span></span>
<span class="line">                    args <span class="token operator">&lt;&lt;</span> error<span class="token punctuation">.</span><span class="token function">toQJSValue</span><span class="token punctuation">(</span><span class="token operator">*</span>engine<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 传入错误信息</span></span>
<span class="line">                    onFailure<span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span><span class="token punctuation">;</span>              <span class="token comment">// 调用 QML 失败回调</span></span>
<span class="line">                <span class="token punctuation">}</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">,</span> Qt<span class="token double-colon punctuation">::</span>QueuedConnection<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 队列连接：确保在主线程执行</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三、step-2-注册-c-单例到-qml" tabindex="-1"><a class="header-anchor" href="#三、step-2-注册-c-单例到-qml"><span>三、Step 2：注册 C++ 单例到 QML</span></a></h2><p>在 <code>main.cpp</code> 中，将 <code>AuthenticationService</code> 单例注册到 QML 上下文，让 QML 可以直接访问：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// main.cpp</span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QGuiApplication&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;QQmlApplicationEngine&gt;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;authentication_service.h&quot;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token keyword">int</span> argc<span class="token punctuation">,</span> <span class="token keyword">char</span> <span class="token operator">*</span>argv<span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    QGuiApplication <span class="token function">app</span><span class="token punctuation">(</span>argc<span class="token punctuation">,</span> argv<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    QQmlApplicationEngine engine<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 注册 C++ 单例到 QML（模块名：backend，版本：1.0，对象名：AuthenticationService）</span></span>
<span class="line">    <span class="token function">qmlRegisterSingletonInstance</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string">&quot;backend&quot;</span><span class="token punctuation">,</span>                <span class="token comment">// QML 导入时的模块名</span></span>
<span class="line">        <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span>                     <span class="token comment">// 版本号（需与 QML import 一致）</span></span>
<span class="line">        <span class="token string">&quot;AuthenticationService&quot;</span><span class="token punctuation">,</span>  <span class="token comment">// QML 中访问的对象名</span></span>
<span class="line">        <span class="token class-name">AuthenticationService</span><span class="token double-colon punctuation">::</span><span class="token function">instance</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// 单例实例</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 加载 QML 主文件</span></span>
<span class="line">    <span class="token keyword">const</span> QUrl <span class="token function">url</span><span class="token punctuation">(</span>u<span class="token string">&quot;qrc:/LoginDemo/main.qml&quot;</span>_qs<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token class-name">QObject</span><span class="token double-colon punctuation">::</span><span class="token function">connect</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>engine<span class="token punctuation">,</span> <span class="token operator">&amp;</span>QQmlApplicationEngine<span class="token double-colon punctuation">::</span>objectCreationFailed<span class="token punctuation">,</span></span>
<span class="line">        <span class="token operator">&amp;</span>app<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token class-name">QCoreApplication</span><span class="token double-colon punctuation">::</span><span class="token function">exit</span><span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        Qt<span class="token double-colon punctuation">::</span>QueuedConnection<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    engine<span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span>url<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">return</span> app<span class="token punctuation">.</span><span class="token function">exec</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>关键注意：</strong></p><ul><li>注册时模块名（<code>backend</code>）、版本号（<code>1.0</code>）必须与 QML 中的 <code>import</code> 语句一致；</li><li>单例注册需用 <code>qmlRegisterSingletonInstance</code>（Qt 5.15+ 支持，Qt 6 推荐），而非 <code>qmlRegisterSingletonType</code>（后者适合动态创建单例）。</li></ul><h2 id="四、step-3-qml-中调用-c-方法并处理回调" tabindex="-1"><a class="header-anchor" href="#四、step-3-qml-中调用-c-方法并处理回调"><span>四、Step 3：QML 中调用 C++ 方法并处理回调</span></a></h2><p>在 QML 界面中，导入注册的模块，调用 <code>AuthenticationService.login</code> 并传入回调函数：</p><div class="language-qml line-numbers-mode" data-highlighter="prismjs" data-ext="qml"><pre><code><span class="line"><span class="token comment">// main.qml</span></span>
<span class="line"><span class="token keyword">import</span> QtQuick 6.2</span>
<span class="line"><span class="token keyword">import</span> QtQuick.Controls 6.2</span>
<span class="line"><span class="token keyword">import</span> backend 1.0 <span class="token comment">// 导入 C++ 注册的模块（需与注册时的模块名、版本一致）</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">ApplicationWindow</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">width</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">400</span></span></span>
<span class="line">    <span class="token property">height</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">300</span></span></span>
<span class="line">    <span class="token property">title</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;登录演示&quot;</span></span></span>
<span class="line">    <span class="token property">visible</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token boolean">true</span></span></span>
<span class="line"></span>
<span class="line">    <span class="token class-name">ColumnLayout</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token property">anchors.centerIn</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript">parent</span></span>
<span class="line">        <span class="token property">spacing</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">16</span></span></span>
<span class="line"></span>
<span class="line">        <span class="token class-name">TextField</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token property">id</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript">usernameField</span></span>
<span class="line">            <span class="token property">placeholderText</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;输入用户名&quot;</span></span></span>
<span class="line">            <span class="token property">Layout.width</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">250</span></span></span>
<span class="line">            <span class="token property">text</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;admin&quot;</span> <span class="token comment">// 测试用默认值</span></span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">        <span class="token class-name">TextField</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token property">id</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript">passwordField</span></span>
<span class="line">            <span class="token property">placeholderText</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;输入密码&quot;</span></span></span>
<span class="line">            <span class="token property">echoMode</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript">TextField<span class="token punctuation">.</span>Password</span></span>
<span class="line">            <span class="token property">Layout.width</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">250</span></span></span>
<span class="line">            <span class="token property">text</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;123456&quot;</span> <span class="token comment">// 测试用默认值（正确密码）</span></span></span>
<span class="line">            <span class="token comment">// text: &quot;wrong&quot; // 测试失败场景</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">        <span class="token class-name">Button</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token property">text</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;登录&quot;</span></span></span>
<span class="line">            <span class="token property">Layout.width</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">250</span></span></span>
<span class="line">            <span class="token property">onClicked</span><span class="token punctuation">:</span> <span class="token punctuation">{</span></span>
<span class="line">                <span class="token comment">// 调用 C++ 的 login 方法，传入回调函数</span></span>
<span class="line">                AuthenticationService.login(</span>
<span class="line">                    usernameField.text<span class="token punctuation">,</span></span>
<span class="line">                    passwordField.text<span class="token punctuation">,</span></span>
<span class="line">                    <span class="token comment">// 成功回调：接收 C++ 传递的响应数据</span></span>
<span class="line">                    function(response) <span class="token punctuation">{</span></span>
<span class="line">                        console.log(<span class="token string">&quot;登录成功！响应：&quot;</span><span class="token punctuation">,</span> JSON.stringify(response))</span>
<span class="line">                        <span class="token comment">// 访问响应属性（C++ 中 LoginResponse 的字段）</span></span>
<span class="line">                        console.log(<span class="token string">&quot;Token:&quot;</span><span class="token punctuation">,</span> response.token)</span>
<span class="line">                        console.log(<span class="token string">&quot;用户名:&quot;</span><span class="token punctuation">,</span> response.username)</span>
<span class="line">                    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">                    <span class="token comment">// 失败回调：接收 C++ 传递的错误信息</span></span>
<span class="line">                    function(error) <span class="token punctuation">{</span></span>
<span class="line">                        console.log(<span class="token string">&quot;登录失败！错误码：&quot;</span><span class="token punctuation">,</span> error.code<span class="token punctuation">,</span> <span class="token string">&quot; 信息：&quot;</span><span class="token punctuation">,</span> error.message)</span>
<span class="line">                        <span class="token comment">// 在界面显示错误提示</span></span>
<span class="line">                        errorLabel.text = error.message</span>
<span class="line">                    <span class="token punctuation">}</span></span>
<span class="line">                )</span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">        <span class="token class-name">Label</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token property">id</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript">errorLabel</span></span>
<span class="line">            <span class="token property">color</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token string">&quot;red&quot;</span></span></span>
<span class="line">            <span class="token property">Layout.width</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript"><span class="token number">250</span></span></span>
<span class="line">            <span class="token property">horizontalAlignment</span><span class="token punctuation">:</span> <span class="token javascript-expression language-javascript">Text<span class="token punctuation">.</span>AlignCenter</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五、核心技术关键点解析" tabindex="-1"><a class="header-anchor" href="#五、核心技术关键点解析"><span>五、核心技术关键点解析</span></a></h2><h3 id="_1-qjsvalue-c-与-qml-回调的桥梁" tabindex="-1"><a class="header-anchor" href="#_1-qjsvalue-c-与-qml-回调的桥梁"><span>1. QJSValue：C++ 与 QML 回调的桥梁</span></a></h3><ul><li><code>QJSValue</code> 是 Qt 中封装 JavaScript 值的类，支持存储函数、对象、基本类型等；</li><li>用 <code>isCallable()</code> 检查是否为可调用的 JavaScript 函数（回调）；</li><li>用 <code>call(QJSValueList args)</code> 调用回调函数，参数通过 <code>QJSValueList</code> 传递。</li></ul><h3 id="_2-线程安全-重中之重" tabindex="-1"><a class="header-anchor" href="#_2-线程安全-重中之重"><span>2. 线程安全（重中之重）</span></a></h3><ul><li>QML 的 <code>QJSEngine</code> 是<strong>线程关联</strong>的（默认绑定主线程），直接在后台线程调用 <code>QJSValue::call</code> 会导致崩溃；</li><li>解决方案：用 <code>QMetaObject::invokeMethod</code> + <code>Qt::QueuedConnection</code>，将回调调用切换到主线程执行。</li></ul><h3 id="_3-自定义数据类型转-qjsvalue" tabindex="-1"><a class="header-anchor" href="#_3-自定义数据类型转-qjsvalue"><span>3. 自定义数据类型转 QJSValue</span></a></h3><ul><li>自定义类（如 <code>KratosError</code>、<code>LoginResponse</code>）需提供 toQJSValue 方法，通过 <code>QJSEngine::newObject()</code> 创建 JS 对象，再用 <code>setProperty</code> 设置属性；</li><li>QML 中可直接通过属性名访问（如 <code>error.message</code>、<code>response.token</code>），大小写敏感。</li></ul><h3 id="_4-有效性检查" tabindex="-1"><a class="header-anchor" href="#_4-有效性检查"><span>4. 有效性检查</span></a></h3><ul><li>必须检查 <code>QJSEngine* engine = qjsEngine(this)</code> 是否为空（避免 QML 组件销毁后引擎失效）；</li><li>必须检查回调函数 <code>isCallable()</code>（避免传入非函数类型导致崩溃）。</li></ul><h2 id="六、常见问题排查" tabindex="-1"><a class="header-anchor" href="#六、常见问题排查"><span>六、常见问题排查</span></a></h2><h3 id="_1-qml-无法导入-backend-模块" tabindex="-1"><a class="header-anchor" href="#_1-qml-无法导入-backend-模块"><span>1. QML 无法导入 backend 模块？</span></a></h3><ul><li>检查 <code>qmlRegisterSingletonInstance</code> 的模块名、版本号与 QML import 一致；</li><li>确保 C++ 类继承 <code>QObject</code> 并添加 <code>Q_OBJECT</code> 宏；</li><li>构建时确保 MOC 文件正常生成（qmake 自动处理，CMake 需添加 <code>qt_add_qml_module</code>）。</li></ul><h3 id="_2-回调函数不执行" tabindex="-1"><a class="header-anchor" href="#_2-回调函数不执行"><span>2. 回调函数不执行？</span></a></h3><ul><li>检查 <code>isCallable()</code> 是否返回 <code>true</code>（确认传入的是函数）；</li><li>检查是否在主线程调用 <code>call()</code>（后台线程调用会静默失败）；</li><li>检查异步逻辑是否正常执行（如模拟的 <code>QThread::sleep</code> 后是否触发回调）。</li></ul><h3 id="_3-程序崩溃" tabindex="-1"><a class="header-anchor" href="#_3-程序崩溃"><span>3. 程序崩溃？</span></a></h3><ul><li>大概率是线程问题：后台线程直接操作 <code>QJSValue</code> 或 <code>QJSEngine</code>；</li><li>检查 <code>engine</code> 是否为空（如单例销毁后仍调用回调）。</li></ul><h2 id="七、最佳实践" tabindex="-1"><a class="header-anchor" href="#七、最佳实践"><span>七、最佳实践</span></a></h2><h3 id="_1-优先使用回调还是信号槽" tabindex="-1"><a class="header-anchor" href="#_1-优先使用回调还是信号槽"><span>1. 优先使用回调还是信号槽？</span></a></h3><ul><li><strong>回调</strong>：适合一次性操作（如登录、单次网络请求），代码直观，参数传递灵活；</li><li><strong>信号槽</strong>：适合多次通知（如实时数据更新），解耦性更强，支持多订阅者；</li><li>本文场景（登录）用回调更合适，简洁高效。</li></ul><h3 id="_2-简化数据传递-可选" tabindex="-1"><a class="header-anchor" href="#_2-简化数据传递-可选"><span>2. 简化数据传递（可选）</span></a></h3><p>若数据简单，可直接用 <code>QVariantMap</code> 代替自定义类，无需写 <code>toQJSValue</code> 方法：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line">QVariantMap errorMap<span class="token punctuation">;</span></span>
<span class="line">errorMap<span class="token punctuation">[</span><span class="token string">&quot;code&quot;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">401</span><span class="token punctuation">;</span></span>
<span class="line">errorMap<span class="token punctuation">[</span><span class="token string">&quot;message&quot;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string">&quot;登录失败&quot;</span><span class="token punctuation">;</span></span>
<span class="line">onFailure<span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>QJSValueList<span class="token punctuation">{</span>engine<span class="token operator">-&gt;</span><span class="token function">toScriptValue</span><span class="token punctuation">(</span>errorMap<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-避免回调地狱" tabindex="-1"><a class="header-anchor" href="#_3-避免回调地狱"><span>3. 避免回调地狱</span></a></h3><p>若存在多层回调（如登录后调用获取用户信息），可考虑用 Qt 6 的 <code>QPromise</code> + <code>co_await</code>（C++20+）或 QML 的 <code>async/await</code> 优化。</p><h2 id="八、总结" tabindex="-1"><a class="header-anchor" href="#八、总结"><span>八、总结</span></a></h2><p>本文完整实现了 Qt 6 中 C++ 调用 QML 回调的流程，核心是：</p><ol><li>C++ 类继承 <code>QObject</code> 并暴露 <code>Q_INVOKABLE</code> 方法；</li><li>用 <code>QJSValue</code> 接收 QML 回调，用 <code>call()</code> 触发回调；</li><li>异步场景下必须切换到主线程执行回调，确保线程安全；</li><li>自定义数据通过 <code>QJSValue</code> 转换后传递，QML 可直接访问属性。</li></ol><p>这种方式适用于所有异步通信场景（登录、网络请求、文件读写等），是 C++ 与 QML 协作的核心技巧之一。</p>`,47)])])}const o=s(t,[["render",l]]),u=JSON.parse('{"path":"/posts/qt_cpp_call_qml_callback.html","title":"Qt 6 实战：C++ 调用 QML 回调方法（异步场景完整实现）","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["C++编程"],"tag":["C++","Qt"],"sticky":10},"headers":[{"level":2,"title":"一、核心场景说明","slug":"一、核心场景说明","link":"#一、核心场景说明","children":[]},{"level":2,"title":"二、Step 1：完善 C++ 服务类","slug":"二、step-1-完善-c-服务类","link":"#二、step-1-完善-c-服务类","children":[{"level":3,"title":"1.1 基础配置（必须继承 QObject）","slug":"_1-1-基础配置-必须继承-qobject","link":"#_1-1-基础配置-必须继承-qobject","children":[]},{"level":3,"title":"1.2 完整 C++ 代码实现","slug":"_1-2-完整-c-代码实现","link":"#_1-2-完整-c-代码实现","children":[]}]},{"level":2,"title":"三、Step 2：注册 C++ 单例到 QML","slug":"三、step-2-注册-c-单例到-qml","link":"#三、step-2-注册-c-单例到-qml","children":[]},{"level":2,"title":"四、Step 3：QML 中调用 C++ 方法并处理回调","slug":"四、step-3-qml-中调用-c-方法并处理回调","link":"#四、step-3-qml-中调用-c-方法并处理回调","children":[]},{"level":2,"title":"五、核心技术关键点解析","slug":"五、核心技术关键点解析","link":"#五、核心技术关键点解析","children":[{"level":3,"title":"1. QJSValue：C++ 与 QML 回调的桥梁","slug":"_1-qjsvalue-c-与-qml-回调的桥梁","link":"#_1-qjsvalue-c-与-qml-回调的桥梁","children":[]},{"level":3,"title":"2. 线程安全（重中之重）","slug":"_2-线程安全-重中之重","link":"#_2-线程安全-重中之重","children":[]},{"level":3,"title":"3. 自定义数据类型转 QJSValue","slug":"_3-自定义数据类型转-qjsvalue","link":"#_3-自定义数据类型转-qjsvalue","children":[]},{"level":3,"title":"4. 有效性检查","slug":"_4-有效性检查","link":"#_4-有效性检查","children":[]}]},{"level":2,"title":"六、常见问题排查","slug":"六、常见问题排查","link":"#六、常见问题排查","children":[{"level":3,"title":"1. QML 无法导入 backend 模块？","slug":"_1-qml-无法导入-backend-模块","link":"#_1-qml-无法导入-backend-模块","children":[]},{"level":3,"title":"2. 回调函数不执行？","slug":"_2-回调函数不执行","link":"#_2-回调函数不执行","children":[]},{"level":3,"title":"3. 程序崩溃？","slug":"_3-程序崩溃","link":"#_3-程序崩溃","children":[]}]},{"level":2,"title":"七、最佳实践","slug":"七、最佳实践","link":"#七、最佳实践","children":[{"level":3,"title":"1. 优先使用回调还是信号槽？","slug":"_1-优先使用回调还是信号槽","link":"#_1-优先使用回调还是信号槽","children":[]},{"level":3,"title":"2. 简化数据传递（可选）","slug":"_2-简化数据传递-可选","link":"#_2-简化数据传递-可选","children":[]},{"level":3,"title":"3. 避免回调地狱","slug":"_3-避免回调地狱","link":"#_3-避免回调地狱","children":[]}]},{"level":2,"title":"八、总结","slug":"八、总结","link":"#八、总结","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":2,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"92b1fa50ff100370b7e4e774591b3ab04a734266","time":1763985353000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add post."}]},"filePathRelative":"posts/qt_cpp_call_qml_callback.md","excerpt":"\\n<p>在 Qt 6 开发中，C++ 与 QML 混合编程是常见场景。当 C++ 处理异步操作（如登录验证、网络请求、数据库查询）时，需要将结果通知给 QML 界面，<strong>回调函数</strong>是最直观的通信方式之一。本文将基于你提供的代码框架，补充关键细节、修复潜在问题，并完整实现从 C++ 调用 QML 回调的全流程。</p>\\n<h2>一、核心场景说明</h2>\\n<p>我们需要实现：</p>\\n<ol>\\n<li>QML 调用 C++ 的 <code>login</code> 方法（传入用户名、密码和两个回调函数：成功回调 <code>onSuccess</code>、失败回调 <code>onFailure</code>）；</li>\\n<li>C++ 异步处理登录逻辑（模拟耗时操作）；</li>\\n<li>登录完成后，C++ 调用对应的 QML 回调函数，将结果（成功响应 / 错误信息）传递给 QML。</li>\\n</ol>"}');export{o as comp,u as data};
